INSERT INTO `movies` VALUES (3,3423380043,NULL,NULL,'admin','Father Interrupted Padrectomia','Release Year: 2024\r\nDuration: 52 minutes\r\nGenre: Social Issue\r\nDirector Guillermo Costanzo\r\nWritten by Guillermo Costanzo and Marcelo Mosenson\r\nLanguage Spanish [latin-america] (with English subtitles)\r\nSynopsis: Father Interrupted - Padrectomía\" is a poignant one-hour documentary from Buenos Aires that follows Marcelo Mosenson, a father struggling to reconnect with his son Noah after three years of legal and emotional obstacles. The film, directed by Guillermo Costanzo, uses Marcelo\'s personal video diaries and includes multiple interviews with other fathers, family law experts, and psychologists to shed light on the issue of parental alienation and its impact on families. Set for release in Spring 2024 and showcasing at Mipcom 2024, the documentary aims to raise global awareness about the challenges faced by fathers fighting for their parental rights.\r\nThe film is co-produced by Nomade Films and Cabracarril, two Argentine companies, and Portuguese production company Luckymatrix.','[\"1600001553\"]','[{\"id\": \"4227419230\", \"role\": \"director\"}, {\"id\": \"3981481360\", \"role\": \"writer\"}]','[]','[{\"id\": \"4227419230\", \"role\": \"director\"}, {\"id\": \"3981481360\", \"role\": \"writer\"}]','5235850799','9320304420','{\"web\":\"3598990015\",\"mobile\":\"3598990015\",\"tv\":\"3598990015\"}','{\"web\":\"6508517940\",\"mobile\":\"6508517940\",\"tv\":\"6508517940\"}','2024-11-07',0,0,NULL,NULL,'active','0',1.99,1.99,NULL,'2025-04-09 07:33:26','2025-10-09 12:43:12'),(22,9092461847,NULL,NULL,'admin','Mahoning Valley','Real People. Real Change. Real Stories: Congratulations to Derrick McDowell, creator of Youngstown Flea and newly elected Mayor of Youngstown. He’s one of the many real voices featured in Mahoning Valley:\r\n\r\nNearly fifty years ago, the Mahoning Valley in Ohio experienced one of the starkest examples of America’s boom and bust. Once the world’s second-largest steel producer, the region was brought to its knees on 19 September 1977 — “Black Monday” — when more than 5,000 workers lost their jobs in a single day. The collapse of the steel industry reshaped the community, leaving scars that still define the political and social landscape of what is now JD Vance’s home state and the stronghold of Trump’s America.\r\n\r\nThis one-hour French documentary looks beyond the political rumble to give voice to the people themselves. Local activists, entrepreneurs, historians, and ordinary witnesses tell a story that spans both past and future — from the loss of an industry to the hopeful reinvention of a community. Filmmakers Jean-François Debos and Jean-François Henane capture not just the hardship, but the resilience, documenting how Mahoning Valley continues to reinvent itself through the determination of its citizens. Featuring: H. William Lawson – Executive Director, Mahoning Valley Historical Society, City of Youngstown; Sean Posey – Historian, City of Campbell; Timothy Sokoloff – President, Iron Soup Historical Preservation Company, City of Campbell; Sean Posey – Historian, City of Campbell; Frank Marr – Retired / Black Monday survivor, City of Struthers; Derrick McDowell – Creator, Youngstown Flea, City of Youngstown; Joseph Pavlansky – Historian, City of Campbell; Catherine Cercone Miller – Mayor, City of Struthers; Christine Kusky – Waitress, Taverne 26, City of Campbell; J. Richard Rowlands – Founder, J&L Narrow Gauge Railroad, City of Youngstown; Tim Roddy – Chief of Police, City of Struthers; Matt Martin – Executive Director, Trumbull Neighborhood Partnership, City of Warren; Shawn Carvin – Executive Director, Ohio Land Bank Association, City of Warren; James Dicenso – Downtown Development Group, City of Warren; Bryan Tedesco – Mayor, City of Campbell.','[\"1600001553\", \"9532289053\", \"4296399229\"]','[{\"id\": \"5539455854\", \"role\": \"director\"}, {\"id\": \"3039455863\", \"role\": \"director\"}]','[]','[{\"id\": \"5539455854\", \"role\": \"director\"}, {\"id\": \"3039455863\", \"role\": \"director\"}]','3206291011','6330993325','{\"web\":2612665027,\"mobile\":2612665027,\"tv\":2612665027}','{\"web\":9000772260,\"mobile\":9000772260,\"tv\":9000772260}','2025-09-17',0,0,NULL,NULL,'active','0',4.99,4.99,NULL,'2025-09-17 13:44:15','2026-04-04 10:26:54'),(24,3866308074,NULL,NULL,'admin','Dealing With Dad','Margaret Chang (Ally Maki) reluctantly returns to her hometown along with her hapless brothers (Hayden Szeto, Peter S. Kim) to deal with the sudden depression of their complete-jerk father (Dana Lee). It turns out Dad is nicer depressed than well, and the siblings wonder if they should even get him better as they struggle to find a solution in this comedic drama.','[\"3620642176\", \"9753701048\"]','[{\"id\": \"398689807\", \"role\": \"actor\"}, {\"id\": \"3874102356\", \"role\": \"actor\"}, {\"id\": \"6569574369\", \"role\": \"actor\"}, {\"id\": \"6734771232\", \"role\": \"actor\"}, {\"id\": \"7223794810\", \"role\": \"actor\"}, {\"id\": \"9457518069\", \"role\": \"director\"}]','[{\"id\": \"398689807\", \"role\": \"actor\"}, {\"id\": \"3874102356\", \"role\": \"actor\"}, {\"id\": \"6569574369\", \"role\": \"actor\"}, {\"id\": \"6734771232\", \"role\": \"actor\"}, {\"id\": \"7223794810\", \"role\": \"actor\"}]','[{\"id\": \"9457518069\", \"role\": \"director\"}]','9271656230','2199842552','{\"web\":6864530031,\"mobile\":6864530031,\"tv\":6864530031}','{\"web\":2392919464,\"mobile\":2392919464,\"tv\":2392919464}','2024-02-22',16,0,NULL,NULL,'active','0',2.99,2.99,NULL,'2025-09-23 14:15:41','2026-04-04 10:29:47'),(25,312057283,NULL,NULL,'admin','Dead Hand','Agent Eoghan Flynn must recruit Johnny Mai in order to take down an international terrorist on the verge of gaining nuclear power.','[\"1086780939\"]','[{\"id\": \"2301599288\", \"role\": \"actor\"}, {\"id\": \"2429105150\", \"role\": \"actor\"}, {\"id\": \"3182140119\", \"role\": \"actor\"}, {\"id\": \"7519444189\", \"role\": \"actor\"}, {\"id\": \"8432206757\", \"role\": \"actor\"}, {\"id\": \"8432206757\", \"role\": \"director\"}]','[{\"id\": \"2301599288\", \"role\": \"actor\"}, {\"id\": \"2429105150\", \"role\": \"actor\"}, {\"id\": \"3182140119\", \"role\": \"actor\"}, {\"id\": \"7519444189\", \"role\": \"actor\"}, {\"id\": \"8432206757\", \"role\": \"actor\"}]','[{\"id\": \"8432206757\", \"role\": \"director\"}]','8140432318','6758588342','{\"web\":385117195,\"mobile\":385117195,\"tv\":385117195}','{\"web\":1684491970,\"mobile\":1684491970,\"tv\":1684491970}','2024-05-22',16,1,8588869491,NULL,'active','0',2.99,2.99,NULL,'2025-09-23 14:16:15','2026-04-04 10:11:40'),(26,455371530,NULL,NULL,'admin','Queer Church','\"The Church in America and the world, they still don\'t know what to do with Queer Folk\" - Pastor Drew Stever . Transgender Pastor Drew and the \"House of the Lord\" hold a controversial Queer Church Service for Queer People and Allies.','[\"1600001553\", \"8278002320\", \"9125856514\"]','[{\"id\": \"566732489\", \"role\": \"actor\"}, {\"id\": \"2971867600\", \"role\": \"actor\"}, {\"id\": \"4577156253\", \"role\": \"actor\"}, {\"id\": \"5917213871\", \"role\": \"actor\"}, {\"id\": \"5921040135\", \"role\": \"actor\"}, {\"id\": \"4121155412\", \"role\": \"director\"}]','[{\"id\": \"566732489\", \"role\": \"actor\"}, {\"id\": \"2971867600\", \"role\": \"actor\"}, {\"id\": \"4577156253\", \"role\": \"actor\"}, {\"id\": \"5917213871\", \"role\": \"actor\"}, {\"id\": \"5921040135\", \"role\": \"actor\"}]','[{\"id\": \"4121155412\", \"role\": \"director\"}]','6321340344','2563342098','{\"web\":2286807899,\"mobile\":2286807899,\"tv\":2286807899}','{\"web\":4793000856,\"mobile\":4793000856,\"tv\":4793000856}','2024-08-02',16,0,NULL,NULL,'active','0',2.99,2.99,NULL,'2025-09-23 14:17:07','2026-04-04 10:23:20'),(27,6096910042,NULL,NULL,'admin','Name the Demon','Name The Demon is a feature length, paranormal, exorcism film presented as one continuous shot.  \r\n\r\nThree years ago, a district court sealed the disturbing video evidence in a murder trial after an exorcism went horribly wrong. Now, that footage has been unsealed for the public. The footage shows the harrowing events of a single night as a band of priests and family confront the darkness within them to save the soul of a mentally tormented woman.\r\n\r\nName The Demon draws Inspiration from the modern style of “Prey for the Devil” and the classic supernatural horror of “The Exorcist.”','[\"4526934488\"]','[{\"id\": \"1052808765\", \"role\": \"actor\"}, {\"id\": \"2364346938\", \"role\": \"actor\"}, {\"id\": \"3153907966\", \"role\": \"actor\"}, {\"id\": \"3637377252\", \"role\": \"actor\"}, {\"id\": \"3671200976\", \"role\": \"actor\"}, {\"id\": \"7199893528\", \"role\": \"director\"}]','[{\"id\": \"1052808765\", \"role\": \"actor\"}, {\"id\": \"2364346938\", \"role\": \"actor\"}, {\"id\": \"3153907966\", \"role\": \"actor\"}, {\"id\": \"3637377252\", \"role\": \"actor\"}, {\"id\": \"3671200976\", \"role\": \"actor\"}]','[{\"id\": \"7199893528\", \"role\": \"director\"}]','8028385192','336294369','{\"web\":5517701047,\"mobile\":5517701047,\"tv\":5517701047}','{\"web\":3601104975,\"mobile\":3601104975,\"tv\":3601104975}','2024-08-16',16,0,NULL,NULL,'active','0',2.99,2.99,NULL,'2025-09-23 14:18:01','2026-04-04 10:18:29'),(28,6967242394,NULL,NULL,'admin','I Survived a Zombie Holocaust','The crew of the New Zealand low budget Zombie film “Tonight They Come!” are filming in the middle of nowhere in one of the rugged country\'s harsh unforgiving forests. Beset with ongoing problems and delays the troubled shoot goes from bad to worse when key cast and crew are struck down by a mystery illness. The replacement Runner, WESLEY PENNINGTON arrives on set fresh out of film school and bubbling with enthusiasm... just in time for the mystery illness to start turning zombie extras into REAL, shuffling, un-dead Zombies. Of course the crew bareley notice, they’ve fallen so far behind schedule and Wesley is the first to discover the zombie outbreak.  Armed with only a prolific knowledge zombie films to help him, he tries to escape the deadly film set with a small group of survivors.','[\"3620642176\", \"4526934488\"]','[{\"id\": \"3518768902\", \"role\": \"actor\"}, {\"id\": \"3725742818\", \"role\": \"actor\"}, {\"id\": \"6325994832\", \"role\": \"actor\"}, {\"id\": \"8895510013\", \"role\": \"actor\"}, {\"id\": \"9221581445\", \"role\": \"actor\"}, {\"id\": \"3725742818\", \"role\": \"director\"}]','[{\"id\": \"3518768902\", \"role\": \"actor\"}, {\"id\": \"3725742818\", \"role\": \"actor\"}, {\"id\": \"6325994832\", \"role\": \"actor\"}, {\"id\": \"8895510013\", \"role\": \"actor\"}, {\"id\": \"9221581445\", \"role\": \"actor\"}]','[{\"id\": \"3725742818\", \"role\": \"director\"}]','3749472052','3752161628','{\"web\":6151471234,\"mobile\":6151471234,\"tv\":6151471234}','{\"web\":2170721609,\"mobile\":2170721609,\"tv\":2170721609}','2024-10-09',16,0,NULL,NULL,'active','0',2.99,2.99,NULL,'2025-09-23 14:18:29','2026-04-04 10:17:25'),(29,5479431496,NULL,NULL,'admin','You Picked the Wrong One','Venus King is the wife of Damon King, a notorious crime boss. Their lives take a dramatic turn when Venus is kidnapped by a group of masked criminals seeking a large ransom. The kidnappers believe they have the upper hand, thinking they\'ve only taken the boss\'s wife. However, they soon discover that Venus is not just the spouse of a crime lord; she is the actual mastermind behind the empire. Revealed to be the true leader, Venus uses her intelligence and understanding of criminal strategy to manipulate her captors. She skillfully turns them against one another, exploiting their weaknesses and fears. As the power dynamics shift, Venus orchestrates her escape, leaving chaos in her wake. The film concludes with her walking away, her power undisputed, having proved that underestimating her is a fatal mistake.','[\"8923932645\", \"2660611023\"]','[{\"id\": \"673267780\", \"role\": \"actor\"}, {\"id\": \"2188872165\", \"role\": \"actor\"}, {\"id\": \"2544760253\", \"role\": \"actor\"}, {\"id\": \"3969072349\", \"role\": \"actor\"}, {\"id\": \"4815672033\", \"role\": \"actor\"}, {\"id\": \"2239652829\", \"role\": \"director\"}, {\"id\": \"5913959968\", \"role\": \"actor\"}]','[{\"id\": \"673267780\", \"role\": \"actor\"}, {\"id\": \"2188872165\", \"role\": \"actor\"}, {\"id\": \"2544760253\", \"role\": \"actor\"}, {\"id\": \"3969072349\", \"role\": \"actor\"}, {\"id\": \"4815672033\", \"role\": \"actor\"}, {\"id\": \"5913959968\", \"role\": \"actor\"}]','[{\"id\": \"2239652829\", \"role\": \"director\"}]','639323216','1321635930','{\"web\":6539815847,\"mobile\":6539815847,\"tv\":6539815847}','{\"web\":5968028729,\"mobile\":5968028729,\"tv\":5968028729}','2025-01-20',16,0,NULL,NULL,'active','0',2.99,2.99,NULL,'2025-09-23 14:19:54','2026-04-04 10:26:28'),(30,8873606292,NULL,NULL,'admin','The Actor','An actor battling his own moral standards witnesses a neighbor\'s murder and stumbles upon a load of cash the victim was hiding. He keeps the money, and in doing so, begins the performance of a lifetime to hide who he really is.','[\"1086780939\", \"3620642176\", \"5057436514\"]','[{\"id\": \"1766865024\", \"role\": \"actor\"}, {\"id\": \"2760493130\", \"role\": \"actor\"}, {\"id\": \"2973810129\", \"role\": \"actor\"}, {\"id\": \"3890877543\", \"role\": \"actor\"}, {\"id\": \"9703454117\", \"role\": \"actor\"}, {\"id\": \"1686773667\", \"role\": \"actor\"}, {\"id\": \"1686773667\", \"role\": \"director\"}]','[{\"id\": \"1766865024\", \"role\": \"actor\"}, {\"id\": \"2760493130\", \"role\": \"actor\"}, {\"id\": \"2973810129\", \"role\": \"actor\"}, {\"id\": \"3890877543\", \"role\": \"actor\"}, {\"id\": \"9703454117\", \"role\": \"actor\"}, {\"id\": \"1686773667\", \"role\": \"actor\"}]','[{\"id\": \"1686773667\", \"role\": \"director\"}]','6098492786','5512151195','{\"web\":6009103234,\"mobile\":6009103234,\"tv\":6009103234}','{\"web\":3170167182,\"mobile\":3170167182,\"tv\":3170167182}','2025-01-23',16,0,NULL,NULL,'active','0',2.99,2.99,NULL,'2025-09-23 14:20:24','2026-04-04 10:11:08'),(31,7033942982,NULL,NULL,'admin','Crazy Texas','Amidst the festive spirit of Christmas in a small Texas town, two sisters find themselves embroiled in a dangerous struggle to safeguard their family wealth and deeply held religious convictions.','[\"4526934488\"]','[{\"id\": \"955382930\", \"role\": \"actor\"}, {\"id\": \"996843621\", \"role\": \"actor\"}, {\"id\": \"2748433585\", \"role\": \"actor\"}, {\"id\": \"7327449635\", \"role\": \"actor\"}, {\"id\": \"8222823447\", \"role\": \"actor\"}, {\"id\": \"9179614935\", \"role\": \"director\"}]','[{\"id\": \"955382930\", \"role\": \"actor\"}, {\"id\": \"996843621\", \"role\": \"actor\"}, {\"id\": \"2748433585\", \"role\": \"actor\"}, {\"id\": \"7327449635\", \"role\": \"actor\"}, {\"id\": \"8222823447\", \"role\": \"actor\"}]','[{\"id\": \"9179614935\", \"role\": \"director\"}]','511124917','5604481822','{\"web\":3980904757,\"mobile\":3980904757,\"tv\":3980904757}','{\"web\":5390949927,\"mobile\":5390949927,\"tv\":5390949927}','2025-04-08',16,0,NULL,NULL,'active','0',2.99,2.99,NULL,'2025-09-23 14:21:06','2026-04-04 10:40:12'),(32,3599046558,NULL,NULL,'admin','Waiting for The Drop: Rise of Superstar DJs','Waiting For The Drop:  Rise of Superstar DJs relives the once-in-a-generation moment when record-spinning DJs became superstars and underground rave music exploded into an overground “EDM” festival scene — and captured the imagination of the world.','[\"1600001553\"]','[{\"id\": \"1588771586\", \"role\": \"actor\"}, {\"id\": \"2026707790\", \"role\": \"actor\"}, {\"id\": \"2105944650\", \"role\": \"actor\"}, {\"id\": \"2352590585\", \"role\": \"actor\"}, {\"id\": \"7940130009\", \"role\": \"actor\"}, {\"id\": \"9229610890\", \"role\": \"actor\"}, {\"id\": \"7940130009\", \"role\": \"director\"}]','[{\"id\": \"1588771586\", \"role\": \"actor\"}, {\"id\": \"2026707790\", \"role\": \"actor\"}, {\"id\": \"2105944650\", \"role\": \"actor\"}, {\"id\": \"2352590585\", \"role\": \"actor\"}, {\"id\": \"7940130009\", \"role\": \"actor\"}, {\"id\": \"9229610890\", \"role\": \"actor\"}]','[{\"id\": \"7940130009\", \"role\": \"director\"}]','6677005577','1613586348','{\"web\":2911590588,\"mobile\":2911590588,\"tv\":2911590588}','{\"web\":2660656082,\"mobile\":2660656082,\"tv\":2660656082}','2025-07-18',16,1,NULL,NULL,'active','0',2.99,2.99,NULL,'2025-09-23 14:22:16','2026-04-04 10:40:20'),(33,5653789503,NULL,NULL,'admin','Shape: When Idolisation Leads to Exclusion','Shape: When Idolisation Leads to Exclusion. The gay community celebrates diversity and equality yet discrimination still exists within it. Gay men are bombarded with unrealistic body image standards through advertising, social media, hook-up apps and the clubbing scene. Cisgendered men who are young, fit, white and masculine are clearly at the top of hierarchy.\r\n\r\nThis important documentary unpacks the damaging beliefs which lead to an obsession over physical appearance and how this manifests in excluding those who don’t meet these unattainable standards.','[\"1600001553\"]','[{\"id\": \"1032345240\", \"role\": \"actor\"}, {\"id\": \"2626349195\", \"role\": \"actor\"}, {\"id\": \"4945886711\", \"role\": \"actor\"}, {\"id\": \"8496818744\", \"role\": \"actor\"}, {\"id\": \"9450526030\", \"role\": \"director\"}]','[{\"id\": \"1032345240\", \"role\": \"actor\"}, {\"id\": \"2626349195\", \"role\": \"actor\"}, {\"id\": \"4945886711\", \"role\": \"actor\"}, {\"id\": \"8496818744\", \"role\": \"actor\"}]','[{\"id\": \"9450526030\", \"role\": \"director\"}]','9001663081','3171795985','{\"web\":5444329280,\"mobile\":5444329280,\"tv\":5444329280}','{\"web\":1256369772,\"mobile\":1256369772,\"tv\":1256369772}','2024-10-08',16,0,NULL,NULL,'active','0',2.99,2.99,NULL,'2025-09-23 14:23:38','2026-04-04 10:10:48'),(37,8722334400,NULL,NULL,'admin','Scooter','Italian  English subtitles\r\n\r\nPippo and Zebra, childhood friends from Aosta, Italy, embark on a nostalgic Vespa journey across Europe to find a French girl they met earlier. Their trip, inspired by the cult film Quadrophenia, is meant to be their last adventure before their lives take different paths. However, a chance encounter with three Kurdish brothers trying to reach England turns their carefree ride into an eye-opening experience. As they travel from the Italian Alps to Dunkerque, France, the young men are forced to confront the realities of the refugee crisis, their own privileges, and their impending adulthood. Their journey becomes a transformative experience that challenges their worldviews and potentially alters their future paths.','[\"3620642176\", \"9753701048\", \"4566223508\", \"4296399229\", \"3177281216\"]','[]','[]','[]','4471971234','4471971235','{\"web\":839175402,\"mobile\":839175402,\"tv\":839175402}','{\"web\":5693890415,\"mobile\":5693890415,\"tv\":5693890415}','2025-11-25',0,0,NULL,NULL,'active','0',NULL,2.99,NULL,'2025-11-25 14:08:01','2026-01-15 05:03:21'),(38,6450618856,NULL,NULL,'admin','The Invisible Player','[ Il Giocatore Invisibile ] (Italy)\r\nItalian  English subtitles\r\nSpecial Jury Award - WorldFest‑Houston\r\nProfessor Nari, a distinguished academic, finds his world turned upside down when he receives an anonymous letter accusing him of a trivial mistake in an article about betrayal. As he becomes consumed by the need to uncover the letter\'s author, his relationships begin to crumble. His young lover Olivia can\'t ease his growing paranoia, and he discovers his wife Anna\'s infidelity with a former student. Meanwhile, his longtime rival, Professor Daverio, who has secretly loved Nari\'s wife for years, commits suicide, seemingly confirming Nari\'s suspicions of guilt. As Nari\'s obsession reaches its peak, the true author of the letter is unexpectedly revealed, forcing him to confront the consequences of his paranoia and the real betrayals in his life.','[\"9753701048\", \"6668166910\", \"3274933160\", \"4296399229\"]','[]','[]','[]','4471975555','4471975512','{\"web\":2430418554,\"mobile\":2430418554,\"tv\":2430418554}','{\"web\":2335044157,\"mobile\":2335044157,\"tv\":2335044157}','2025-11-25',0,1,NULL,NULL,'active','0',NULL,2.99,NULL,'2025-11-25 14:17:26','2026-04-04 10:38:25'),(39,7979657233,NULL,NULL,'admin','Stop Fire and Rehire','Watch free on Amavizion. Because this story belongs to everyone!\r\n***\r\nStop Fire and Rehire is a rare thing in political documentary, a story with a happy ending. When MP Barry Gardiner introduced his Private Member\'s Bill to ban fire and rehire in 2021, the Conservative government blocked it. Workers, unions and campaigners refused to give up. In 2024, Labour won the election on a platform that included ending this exploitative practice for good. By 2025, the Employment Rights Act had received Royal Assent and from January 2027, firing workers to rehire them on worse terms will be regarded as unfair dismissal in the UK. Watch where it started.','[\"1600001553\"]','[]','[]','[]','9271656246','9271656247','{\"web\":8797440702,\"mobile\":8797440702,\"tv\":8797440702}','{\"web\":1069802253,\"mobile\":1069802253,\"tv\":1069802253}','2022-02-15',0,0,NULL,NULL,'active','0',NULL,NULL,NULL,'2026-03-06 11:34:26','2026-03-09 08:13:31'),(40,386182613,NULL,NULL,'admin','Mr. Arkadin','Mr. Arkadin (AKA Confidential Report)\r\nA shadowy, super-rich oligarch named Gregory Arkadin claims to have no memory of his life before 1927. He hires small-time smuggler Guy Van Stratten to investigate his own mysterious past — but as Van Stratten traces Arkadin\'s dark origins across Europe, the witnesses he interviews keep turning up dead, and he begins to fear he knows far too much for his own good.','[\"1522695765\", \"5057436514\", \"9753701048\", \"7689560156\", \"2660611023\"]','[{\"id\": \"7169257361\", \"role\": \"actor\"}, {\"id\": \"6921444317\", \"role\": \"actor\"}, {\"id\": \"5812402183\", \"role\": \"actor\"}, {\"id\": \"7169257361\", \"role\": \"director\"}]','[{\"id\": \"7169257361\", \"role\": \"actor\"}, {\"id\": \"6921444317\", \"role\": \"actor\"}, {\"id\": \"5812402183\", \"role\": \"actor\"}]','[{\"id\": \"7169257361\", \"role\": \"director\"}]','9271656251','3814738227','{\"web\":3882601786,\"mobile\":3882601786,\"tv\":3882601786}','{\"web\":2681320810,\"mobile\":2681320810,\"tv\":2681320810}','1955-03-01',0,1,NULL,NULL,'active','0',1.49,1.49,NULL,'2026-03-08 11:15:29','2026-04-04 10:10:02'),(41,7138157917,NULL,NULL,'admin','Life with Father','In late-19th-century New York City, Wall Street stockbroker Clarence Day Sr. rules his household — or so he thinks. Surrounded by his four red-haired sons and a wife far cleverer than she lets on, the blustering patriarch meets his match at every turn. The comedy reaches its peak when it\'s revealed he has never been baptised, sending his devout wife Vinnie on a determined mission to remedy the situation once and for all.','[\"3620642176\", \"1883188751\"]','[{\"id\": \"3015088977\", \"role\": \"actor\"}, {\"id\": \"850212334\", \"role\": \"actress\"}, {\"id\": \"6608295344\", \"role\": \"actress\"}, {\"id\": \"7878708701\", \"role\": \"director\"}]','[{\"id\": \"3015088977\", \"role\": \"actor\"}, {\"id\": \"850212334\", \"role\": \"actress\"}, {\"id\": \"6608295344\", \"role\": \"actress\"}]','[{\"id\": \"7878708701\", \"role\": \"director\"}]','9271656250',NULL,NULL,NULL,'1947-08-14',0,0,NULL,NULL,'deactive','0',1.49,1.49,NULL,'2026-03-08 11:17:47','2026-03-31 14:51:50'),(42,5923091782,NULL,NULL,'admin','Man in the Attic','London, 1888. As Jack the Ripper\'s murders grip the city in terror, the mysterious Mr. Slade — a quietly menacing research pathologist — takes lodgings with the Harley household, renting out the attic for his \"experiments.\" His landlady grows increasingly suspicious of his late-night outings and odd behaviour. When Lily Bonner, a beautiful stage actress and the Harleys\' niece, arrives and finds herself drawn to the brooding lodger, the tension mounts — is Slade the Ripper, and is Lily his next victim?','[\"5057436514\", \"9753701048\", \"9532289053\", \"7689560156\", \"2660611023\"]','[{\"id\": \"2253620591\", \"role\": \"actor\"}, {\"id\": \"4511339025\", \"role\": \"actress\"}, {\"id\": \"767513924\", \"role\": \"actor\"}, {\"id\": \"3087169277\", \"role\": \"director\"}]','[{\"id\": \"2253620591\", \"role\": \"actor\"}, {\"id\": \"4511339025\", \"role\": \"actress\"}, {\"id\": \"767513924\", \"role\": \"actor\"}]','[{\"id\": \"3087169277\", \"role\": \"director\"}]','9271656249',NULL,NULL,NULL,'1953-12-23',0,0,NULL,NULL,'deactive','0',1.49,1.49,NULL,'2026-03-08 11:19:52','2026-03-31 14:49:18'),(43,9537950109,NULL,NULL,'admin','The Last Time I Saw Paris','Here is the admin entry for the_last_time_i_saw_paris.mp4:\r\n\r\nTitle: The Last Time I Saw Paris\r\n\r\nDescription: As World War II ends in Europe, American journalist Charles Wills arrives in Paris to cover the liberation celebrations — and finds himself swept up in something far more personal. He falls for the vivacious, beautiful Helen Ellswirth, and they marry. But when unexpected wealth arrives, their lives begin to unravel in ways neither could have predicted, and a sudden tragedy will haunt Charles for years to come. Shot in glorious Technicolor, this bittersweet love story unfolds through memory and longing — a man trying to make sense of what Paris gave him, and what it took away.','[\"9753701048\", \"4566223508\"]','[{\"id\": \"6608295344\", \"role\": \"actress\"}, {\"id\": \"9099742248\", \"role\": \"actor\"}, {\"id\": \"3053807986\", \"role\": \"actor\"}, {\"id\": \"5393595050\", \"role\": \"director\"}]','[{\"id\": \"6608295344\", \"role\": \"actress\"}, {\"id\": \"9099742248\", \"role\": \"actor\"}, {\"id\": \"3053807986\", \"role\": \"actor\"}]','[{\"id\": \"5393595050\", \"role\": \"director\"}]','9271656252',NULL,NULL,NULL,'1954-03-23',0,0,NULL,NULL,'deactive','0',1.49,1.49,NULL,'2026-03-08 15:40:54','2026-03-31 14:46:52'),(44,9763247807,NULL,NULL,'admin','A Time for Dying','Description: In the lawless town of Silver City, young farm boy Cass Bunning arrives with a quick draw and big ambitions of becoming a bounty hunter. After a chance encounter forces him and a naive saloon girl, Nellie, into a shotgun wedding presided over by the notorious Judge Roy Bean, the two try to make a life together — only for Cass to cross paths with Jesse James himself.','[\"9753701048\"]','[{\"id\": \"2475385160\", \"role\": \"actor\"}, {\"id\": \"5950274078\", \"role\": \"actress\"}, {\"id\": \"6879801738\", \"role\": \"actor\"}, {\"id\": \"5167228941\", \"role\": \"director\"}]','[{\"id\": \"2475385160\", \"role\": \"actor\"}, {\"id\": \"5950274078\", \"role\": \"actress\"}, {\"id\": \"6879801738\", \"role\": \"actor\"}]','[{\"id\": \"5167228941\", \"role\": \"director\"}]','9271656248',NULL,NULL,NULL,'1969-02-05',0,0,NULL,NULL,'deactive','0',1.49,1.49,NULL,'2026-03-08 15:43:16','2026-03-31 14:43:28'),(45,6459814457,NULL,NULL,'admin','The Man with the Golden Arm','Nelson Algren\'s groundbreaking 1949 novel shook American literature. Otto Preminger\'s film shook Hollywood.\r\nFrankie \"Machine\" Majcinek (Sinatra) walks out of prison clean — off heroin and with a dream of becoming a jazz drummer. But the Chicago slum neighbourhood that swallowed him before is waiting: the card sharks want their dealer back, and his manipulative wife Zosh (Eleanor Parker) refuses to let him go, playing on his guilt to keep him trapped. His only real hope is Molly (Kim Novak), a warm-hearted neighbour who believes in the man Frankie could be — and loves him enough to fight for it.','[\"1522695765\", \"9753701048\"]','[{\"id\": \"6585362739\", \"role\": \"actor\"}, {\"id\": \"8723794619\", \"role\": \"actress\"}, {\"id\": \"4288374325\", \"role\": \"actress\"}, {\"id\": \"2504056732\", \"role\": \"director\"}]','[{\"id\": \"6585362739\", \"role\": \"actor\"}, {\"id\": \"8723794619\", \"role\": \"actress\"}, {\"id\": \"4288374325\", \"role\": \"actress\"}]','[{\"id\": \"2504056732\", \"role\": \"director\"}]','9271656253','734708523','{\"web\":1116289300,\"mobile\":1116289300,\"tv\":1116289300}','{\"web\":7509603485,\"mobile\":7509603485,\"tv\":7509603485}','1955-05-17',13,1,NULL,NULL,'active','0',2.49,2.49,NULL,'2026-03-08 15:51:33','2026-04-04 10:33:16'),(46,7009560886,NULL,NULL,'admin','The Terror','Director: Roger Corman (with uncredited second unit work by Francis Ford Coppola, Monte Hellman and Jack Nicholson)\r\n***\r\nNapoleonic France, 1806. Lieutenant André Duvalier, separated from his regiment near the Baltic coast, is bewitched by a mysterious and beautiful woman who vanishes as suddenly as she appears. Tracking her to a crumbling gothic castle, he finds the brooding, tormented Baron von Leppe — a man haunted by the ghost of his dead wife Ilsa. But is Helene truly a ghost, or a pawn in a far darker game of witchcraft and revenge? As secrets buried for twenty years begin to surface, Duvalier realises some doors should never be opened.','[\"1522695765\", \"9753701048\", \"9532289053\", \"4526934488\", \"6668166910\"]','[{\"id\": \"5017103575\", \"role\": \"director\"}, {\"id\": \"9032682982\", \"role\": \"actor\"}, {\"id\": \"5892107649\", \"role\": \"actor\"}, {\"id\": \"8590572923\", \"role\": \"actress\"}, {\"id\": \"5879002505\", \"role\": \"director\"}, {\"id\": \"7149011473\", \"role\": \"director\"}]','[{\"id\": \"9032682982\", \"role\": \"actor\"}, {\"id\": \"5892107649\", \"role\": \"actor\"}, {\"id\": \"8590572923\", \"role\": \"actress\"}]','[{\"id\": \"5017103575\", \"role\": \"director\"}, {\"id\": \"5879002505\", \"role\": \"director\"}, {\"id\": \"7149011473\", \"role\": \"director\"}]','9271656254',NULL,NULL,NULL,'1963-06-17',0,0,NULL,NULL,'deactive','0',1.49,1.49,NULL,'2026-03-08 15:54:48','2026-03-31 14:40:11'),(47,2617097438,NULL,NULL,'admin','Miss Conception','Georgina Salt has it all — a thriving London construction company, a long-term boyfriend, and a plan for everything. Everything except time. When her doctor delivers the bombshell that she has only days left to conceive before it\'s too late forever, Georgina\'s neat little plan for motherhood goes spectacularly off the rails. With her baby-phobic boyfriend conveniently away on a remote island with a suspiciously beautiful heiress, Georgina and her irrepressibly optimistic friend Clem embark on an increasingly chaotic — and very funny — hunt for the perfect father. A warm, witty romantic comedy about biological clocks, bad timing, and the surprising places love turns up','[\"3620642176\", \"4566223508\"]','[{\"id\": \"7815333143\", \"role\": \"actress\"}, {\"id\": \"6214453667\", \"role\": \"actress\"}, {\"id\": \"8361521339\", \"role\": \"actor\"}, {\"id\": \"6560819664\", \"role\": \"director\"}]','[{\"id\": \"7815333143\", \"role\": \"actress\"}, {\"id\": \"6214453667\", \"role\": \"actress\"}, {\"id\": \"8361521339\", \"role\": \"actor\"}]','[{\"id\": \"6560819664\", \"role\": \"director\"}]','872492560','4388651236','{\"web\":6848636735,\"mobile\":6848636735,\"tv\":6848636735}','{\"web\":5556588189,\"mobile\":5556588189,\"tv\":5556588189}','2008-01-01',13,1,NULL,NULL,'active','0',2.99,2.99,NULL,'2026-03-09 08:11:37','2026-04-04 10:32:05'),(48,4433355875,NULL,NULL,'admin','Empty Nets  تورهای خالی','Version Originale, Farsi, English Subtitles.\r\n\r\nAmir and Narges are in love on the Caspian coast of Iran — but love does not pay a dowry. To earn the money tradition demands of him, Amir takes work at a fishery and is drawn into the world of black-market caviar smuggling, risking everything he is trying to build. \r\nBehrooz Karamizade\'s debut feature is socially precise and romantically charged, shot with the directness of Iranian neorealism and selected for the Karlovy Vary Crystal Globe Competition, the Tromsø International Film Festival, the El Gouna Film Festival, and the Nuremberg International Human Rights Film Festival.\r\n\r\nA confidently quiet, elegiac first feature — European arthouse sheen to a story steeped in the stark tradition of Iranian social realism.\"\r\n— Guy Lodge, Variety\r\n\r\n\"A piercing, powerful debut… shines a light on the economic realities of Iran for young people who can barely afford to dream.\"\r\n— Wendy Ide, Screen International\r\n\r\n\"Socially conscious neorealism at its best.\"\r\n— Frank Scheck, Hollywood Reporter\r\n\r\n\"A suitably seductive aquatic-blue palette that reflects its all-consuming vision of a man who\'s, metaphorically, lost at sea.\"\r\n— Damon Wise, Deadline','[\"9753701048\", \"4566223508\", \"3274933160\", \"4296399229\", \"2660611023\"]','[{\"id\": \"212316498\", \"role\": \"actor\"}, {\"id\": \"3342475097\", \"role\": \"actress\"}, {\"id\": \"4176571709\", \"role\": \"actor\"}, {\"id\": \"7970823047\", \"role\": \"director\"}]','[{\"id\": \"212316498\", \"role\": \"actor\"}, {\"id\": \"3342475097\", \"role\": \"actress\"}, {\"id\": \"4176571709\", \"role\": \"actor\"}]','[{\"id\": \"7970823047\", \"role\": \"director\"}]','4334937422','1282424238','{\"web\":5252836222,\"mobile\":5252836222,\"tv\":5252836222}','{\"web\":8196513471,\"mobile\":8196513471,\"tv\":8196513471}','2023-06-25',13,0,NULL,NULL,'active','0',2.49,2.49,NULL,'2026-04-05 10:23:38','2026-04-05 10:55:58'),(49,5685271674,NULL,NULL,'admin','Baba Yaga','A photographer finds herself falling under the spell of a witch.','[\"4526934488\"]','[{\"id\": \"6802764945\", \"role\": \"actor\"}, {\"id\": \"6158608251\", \"role\": \"actress\"}, {\"id\": \"5020140356\", \"role\": \"actress\"}, {\"id\": \"2174036454\", \"role\": \"director\"}]','[{\"id\": \"6802764945\", \"role\": \"actor\"}, {\"id\": \"6158608251\", \"role\": \"actress\"}, {\"id\": \"5020140356\", \"role\": \"actress\"}]','[{\"id\": \"2174036454\", \"role\": \"director\"}]',NULL,NULL,NULL,NULL,NULL,0,0,NULL,NULL,'deactive','0',NULL,NULL,NULL,'2026-04-07 15:37:57','2026-04-07 16:26:00'),(50,279659468,NULL,NULL,'admin','La Corta Notte delle Bambole di Vetro','An American journalist temporarily stationed in Central Europe searches for his new girlfriend, who has suddenly disappeared.','[\"4526934488\"]','[{\"id\": \"1404089412\", \"role\": \"actor\"}, {\"id\": \"8123158704\", \"role\": \"actress\"}, {\"id\": \"2664057300\", \"role\": \"actor\"}, {\"id\": \"465400046\", \"role\": \"director\"}]','[{\"id\": \"1404089412\", \"role\": \"actor\"}, {\"id\": \"8123158704\", \"role\": \"actress\"}, {\"id\": \"2664057300\", \"role\": \"actor\"}]','[{\"id\": \"465400046\", \"role\": \"director\"}]',NULL,NULL,NULL,NULL,NULL,0,0,NULL,NULL,'deactive','0',NULL,NULL,NULL,'2026-04-07 16:03:34','2026-04-07 16:30:43'),(51,3962785296,NULL,NULL,'admin','Django sfida Sartana','Framed for a bank robbery, bounty killer Django\'s brother, Steve is lynched. Django hunts down Sartana, Steve\'s supposed accomplice, but finds him innocent also. The two men seek out the real robbers.','[\"184804758\"]','[{\"id\": \"6448333181\", \"role\": \"actor\"}, {\"id\": \"3092304795\", \"role\": \"actor\"}, {\"id\": \"2796481318\", \"role\": \"actor\"}, {\"id\": \"6349169253\", \"role\": \"director\"}]','[{\"id\": \"6448333181\", \"role\": \"actor\"}, {\"id\": \"3092304795\", \"role\": \"actor\"}, {\"id\": \"2796481318\", \"role\": \"actor\"}]','[{\"id\": \"6349169253\", \"role\": \"director\"}]',NULL,NULL,NULL,NULL,NULL,0,0,NULL,NULL,'deactive','0',NULL,NULL,NULL,'2026-04-07 16:16:11','2026-04-07 16:28:08'),(52,2618983354,NULL,NULL,'admin','Flavia, la monaca musulmana','A young woman forced into nun-hood by her corrupt father teams up with an army of Muslims to destroy the convent and kill those who wronged her.','[\"9753701048\", \"4526934488\"]','[{\"id\": \"3373194192\", \"role\": \"actress\"}, {\"id\": \"6142740373\", \"role\": \"actress\"}, {\"id\": \"1271833308\", \"role\": \"actor\"}, {\"id\": \"2617675563\", \"role\": \"director\"}]','[{\"id\": \"33731941